var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"1개월 뒤","JPN":"1か月後","ENG":"1 month later","TWN":"1個月後","SCN":"1个月后","DEU":"1 month later","FRA":"1 month later"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>샤레이드 건틀렛 리그</color> 본선 진행 중","JPN":"<color=#ffd34c>シャレードガントレットリーグ</color>本選進行中","ENG":"<color=#ffd34c>Charade Gauntlet League</color> Elimination Rounds","TWN":"<color=#ffd34c>查雷德聖鎧聯賽</color>決賽進行中","SCN":"<color=#ffd34c>查雷德圣铠联赛</color>决赛 进行中","DEU":"<color=#ffd34c>Charade Gauntlet League</color> Elimination Rounds","FRA":"<color=#ffd34c>Charade Gauntlet League</color> Elimination Rounds"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"제가 있으니까 라이카는 너무 걱정하지 않으셔도 괜찮아요, 사장님.","JPN":"私がついていますから、ライカのことはあまり心配しなくて大丈夫ですよ、社長。","ENG":"You don't have to worry about Laika, Coach. I'll be with her.","TWN":"老闆放心，有我在，萊卡不會有事的。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"알겠네. 그럼, 부탁하지.","JPN":"わかった。では、頼む。","ENG":"Very well. Then I'll leave her to you.","TWN":"好，那就麻煩你了。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"오래된 목소리, 들립니까?","JPN":"古い声、聞こえますか？","ENG":"Old Voice, do you hear me?","TWN":"老聲音，有聽到嗎？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"잘 들리네, 엘리자베스 양. 부탁한 조사는 끝내두었나?","JPN":"ちゃんと聞こえているよ、エリザベス君。頼んでいた調査は終わったかね？","ENG":"Loud and clear, Elizabeth. Have you finished the investigation I asked about?","TWN":"我有聽到，伊莉莎白。我拜託你調查的事有結果嗎？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"게임 이후에는 뭔가 달라질 것처럼 당당하게 자기 정체를 공표하더니.","JPN":"ゲームの後、人が変わったみたいに堂々と自分の正体を公表したくせに。","ENG":"You proclaimed your identity with such pride, as if something were to change in the aftermath of the game.","TWN":"遊戲之後，好像哪裡不太一樣，你竟然毫不隱藏自己的身分。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"뒤에서는 여전히 자기 요청만 밀어붙이시는군요, 오래된 목소리께서는.","JPN":"裏では相変わらず自分の要望ばかり押しつけるのですね、古い声は。","ENG":"But you're still merely requesting favours from behind the veil, Old Voice.","TWN":"然後還一直提出自己的需求。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 면목이 없네만. 아티팩트에 대한 분석과 조사는 자네들만한 전문가가 없지 않나?","JPN":"はは、面目ない。アーティファクトの分析と調査において、君たち以上の専門家はいないだろう？","ENG":"Ha ha. I am all out of excuses. However, you are the expert when it comes to analyzing and examining Artifacts, are you not?","TWN":"哈哈，真是不好意思，但要講到有關人造神器的分析和調查，你們畢竟是這個領域的佼佼者嘛？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 분야에 있어서는 관리국보다도 자네들이 몇 수나 뛰어나니까 말이야.","JPN":"あの分野においては、管理局より君たちが何倍も優れているからな。","ENG":"You are leagues ahead in that field than the Administration, after all.","TWN":"你們甚至比管理局還厲害呢。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"흠. 말은 그럴싸하게 하시는군요.","JPN":"ふーん。お世辞が上手ですこと。","ENG":"Hmm. It appears that your silver tongue remains intact.","TWN":"哼，話說得真好聽。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Mh?","TWN":"嗯？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그래봤자, 어차피 당신 밑에서 싸구려 탐정 사무소 같은 의뢰나 받는 실정 아닌가요?","JPN":"そうは言っても、現実はあなたの下で安い探偵事務所のようにこき使われているのでしょう？","ENG":"Nevertheless, the truth is that you utilize our services as if we were your cost-effective detective agency.","TWN":"說得那麼好聽，我們根本只是你手下的廉價偵探事務所吧？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"클리포트 게임 이후로 오랜만이네요. 오래된 목소리.","JPN":"クリフォトゲーム以来、お久しぶりですわね。古い声。","ENG":"It has been a while since our last encounter amidst the Qliphoth Game, Old Voice.","TWN":"在逆卡巴拉遊戲之後，我們好久不見囉，老聲音。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"아니. 직접 대면하는 건 처음인가요, 최고 관리자?","JPN":"いいえ。直接顔を合わせるのは初めてでしょうか。最高管理者。","ENG":"No. I believe this is our first time meeting in person, Supreme Administrator.","TWN":"不對，這應該是我們第一次面對面說話吧，最高管理者？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이거…… 기관장께서 직접 샤레이드까지 행차하셨군.","JPN":"これは……機関長自らシャレードまでおいでになるとはね。","ENG":"Oh, my... The chief of Prydwen has come to Charade herself.","TWN":"這是……機關長竟然大駕光臨查雷德。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"틀림없이 음흉한 노인네인 줄 알았는데, 다시봐도 실물은 믿을 수가 없군요.","JPN":"陰気な老人だろうと思っていましたのに、予想外ですわ。","ENG":"I expected you to be an unpleasant old man. I still cannot believe this is your real face.","TWN":"我還以為會是個老奸巨猾的老人，親眼見到後真是不敢相信我的眼睛。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 내가 본래 동안이라네.","JPN":"はは、私はもともと童顔なのだよ。","ENG":"Ha ha, I do look pretty young.","TWN":"哈哈，我本來就是娃娃臉啦。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어쨌든 서로 사담이나 나눌 시간이 없는 건 마찬가지일텐데?","JPN":"とにかく、雑談している暇がないというのはお互い様ではないか？","ENG":"Anyway, I doubt we have time for small talk.","TWN":"不過我們彼此都很忙，應該沒時間閒聊吧？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"걱정마세요, 아무리 바빠도 티타임은 가질 여유는 남겨두는 편이니까요.","JPN":"お気遣いなく。いくら忙しくても、ティータイムの余裕は残しておくタイプですので。","ENG":"Don't worry. I always make time for tea, regardless of how busy I am.","TWN":"你放心，再怎麼忙，喝杯下午茶的時間還是有的。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"새로 들인 홍차가 향이 좋으니, 가여운 고양이 이야기는 홍차와 함께 나누시죠.","JPN":"新しく買った紅茶の香りが素晴らしいんです。かわいそうなネコの話は紅茶をいただきながらにしましょう。","ENG":"This new black tea is delicious. Join me for a cup of tea while you tell me the story of your poor kitten.","TWN":"最近新進的紅茶香氣很不錯，我們就邊喝邊聊聊可憐貓咪的事吧。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"……콜드 케이스 88번에 관한 첩보는 여기까지랍니다.","JPN":"……コールドケースNo.88に関する諜報はここまでですわ。","ENG":"...This is all the intel related to Cold Case No. 88.","TWN":"……關於Cold Case 88號的資料差不多季這樣。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"잘 알겠네, 역시 자네들은 의지할 만하군.","JPN":"わかった、やはり君たちは頼れるな。","ENG":"Very well. I knew I could count on you.","TWN":"我知道了，還是你們靠得住。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"은근슬쩍 감언이설로 넘어갈 생각하지 마시죠.","JPN":"さりげなく口車に乗せようとしないでください。","ENG":"Don't try to wheedle your way out of this.","TWN":"不要想用花言巧語蒙混過關。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};